function safeIdentifier(name) {
  const identifier = name.replace(/[^A-Za-z0-9_$]/g, '_');
  return /^[A-Za-z_$]/.test(identifier) ? identifier : `_${identifier}`;
}

function stableJson(value) {
  if (value === null || typeof value !== 'object') return JSON.stringify(value);
  if (Array.isArray(value)) return `[${value.map(stableJson).join(',')}]`;
  return `{${Object.entries(value)
    .filter(([, item]) => item !== undefined)
    .sort(([left], [right]) => left.localeCompare(right))
    .map(([key, item]) => `${JSON.stringify(key)}:${stableJson(item)}`)
    .join(',')}}`;
}

export function emitJavaScript(document, options = {}) {
  const lines = [];
  const banner = options.banner ?? 'Generated by @shapeshift-labs/frontier-lang-javascript.';
  lines.push(`// ${banner}`, '');
  for (const node of Object.values(document.nodes)) {
    if (node.kind === 'lattice') {
      lines.push(`export const ${safeIdentifier(node.name)}Lattice = Object.freeze(${stableJson({
        name: node.name,
        carrier: node.carrier,
        laws: node.laws ?? [],
        frontierCrdt: node.frontierCrdt
      })});`, '');
    }
  }
  for (const node of Object.values(document.nodes)) {
    if (node.kind === 'entity' || node.kind === 'type') {
      lines.push(`export const ${safeIdentifier(node.name)}Schema = Object.freeze(${stableJson({
        kind: node.kind,
        name: node.name,
        fields: node.fields ?? [],
        variants: node.variants ?? []
      })});`, '');
    }
  }
  for (const node of Object.values(document.nodes)) {
    if (node.kind === 'extern') {
      lines.push(`export function ${safeIdentifier(node.name)}() {`, `  throw new Error(${JSON.stringify(`Extern ${node.name} must be provided by the host runtime.`)});`, '}', '');
    }
  }
  for (const node of Object.values(document.nodes)) {
    if (node.kind === 'action') {
      lines.push(`export function ${safeIdentifier(node.name)}(state, input, env = {}) {`, '  void state;', '  void input;', '  void env;', '  return [];', '}', '');
    }
  }
  return `${lines.join('\n').trimEnd()}\n`;
}
